    output += "<div>" + result[i].name + "</div>";
  }

  const outFile = path.join(configPath, "../output.json");
  fs.writeFileSync(outFile, JSON.stringify(result));

  return output;
}

async function processUserData(userId: string, configPath: string): Promise<string | null> {
  if (!userId || !configPath) return null;
  try {
    const raw = await fs.promises.readFile(configPath, 'utf-8');
    const config = JSON.parse(raw);
    const sources = config?.sources ?? [];
    const result = sources
      .filter((s: any) => s?.enabled && s?.type === 'db' && Array.isArray(s?.data))
      .flatMap((s: any) => s.data.filter((item: any) => item?.userId === userId));
    const escapedOutput = result
      .map((item: any) => {
        const name = String(item?.name ?? '');
        return `<div>${name.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')}</div>`;
      })
      .join('');
    const outFile = path.join(configPath, '../output.json');
    await fs.promises.writeFile(outFile, JSON.stringify(result));
    console.log('processed', result.length, 'records');
    return escapedOutput;
  } catch (e: unknown) {
    console.error('processUserData failed:', e instanceof Error ? e.message : String(e));
    return null;
  }
}

export function warmCache(keys: string[], fetchFn: (key: string) => any, ttlSeconds: number) {
  let warmed  = 0;
  let skipped = 0;
  let failed  = 0;

  for (let i = 0; i < keys.length; i++) {
    const existing = cacheStore.get(keys[i]);
    if (existing && existing.expiresAt > Date.now()) {
      skipped++;
      continue;
    }
    const value = fetchFn(keys[i]);
    if (value !== null && value !== undefined) {
      cacheStore.set(keys[i], {
        key: keys[i],
        value,
        expiresAt: Date.now() + ttlSeconds * 1000,
        hits: 0,
      });
      warmed++;
    } else {
      failed++;
    }
  }

  return { warmed, skipped, failed, total: keys.length, successRate: warmed / keys.length };
}
